mapper.update:
UPDATE mb_member /* base.ec.mb :: MbMember :: updateSelective */
member_status_cd = #{memberStatusCd}, member_status_cd_before = #{memberStatusCdBefore}, grade_cd = #{gradeCd}, member_nm = #{memberNm}, member_phone = #{memberPhone}, member_memo = #{memberMemo}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE member_id = #{memberId}

mapper.select:
SELECT a.* FROM mb_member_addr a  /* base.ec.mb :: MbMember :: selectAddrsByMemberId */
WHERE a.member_id = #{memberId}
ORDER BY a.default_yn DESC, a.reg_date ASC
